// DIAGNOSTIC: Test Google Sheets access methods
const SHEET_ID = '1gMSYFW6ZsJpIkyXQQZOxczfr1ryLC3pb1TI3C_-2v-E';
const results = {};

// Method 1: httpRequestWithAuthentication with json:true
try {
  console.log('Method 1: httpRequestWithAuthentication + json:true');
  const resp1 = await this.helpers.httpRequestWithAuthentication.call(this, 'googleSheetsOAuth2Api', {
    method: 'GET',
    url: 'https://sheets.googleapis.com/v4/spreadsheets/' + SHEET_ID + '/values/Sheet1!A:A',
    json: true,
  });
  results.method1 = { type: typeof resp1, keys: Object.keys(resp1 || {}), hasValues: !!(resp1 && resp1.values), rowCount: (resp1 && resp1.values) ? resp1.values.length : 0 };
  console.log('Method 1 result: ' + JSON.stringify(results.method1));
} catch(e) {
  results.method1 = { error: e.message };
  console.log('Method 1 error: ' + e.message);
}

// Method 2: httpRequestWithAuthentication without json flag
try {
  console.log('Method 2: httpRequestWithAuthentication no json flag');
  const resp2 = await this.helpers.httpRequestWithAuthentication.call(this, 'googleSheetsOAuth2Api', {
    method: 'GET',
    url: 'https://sheets.googleapis.com/v4/spreadsheets/' + SHEET_ID + '/values/Sheet1!A:A',
  });
  const parsed = typeof resp2 === 'string' ? JSON.parse(resp2) : resp2;
  results.method2 = { type: typeof resp2, parsedKeys: Object.keys(parsed || {}), hasValues: !!(parsed && parsed.values), rowCount: (parsed && parsed.values) ? parsed.values.length : 0 };
  console.log('Method 2 result: ' + JSON.stringify(results.method2));
} catch(e) {
  results.method2 = { error: e.message };
  console.log('Method 2 error: ' + e.message);
}

// Method 3: httpRequestWithAuthentication with returnFullResponse
try {
  console.log('Method 3: httpRequestWithAuthentication + returnFullResponse');
  const resp3 = await this.helpers.httpRequestWithAuthentication.call(this, 'googleSheetsOAuth2Api', {
    method: 'GET',
    url: 'https://sheets.googleapis.com/v4/spreadsheets/' + SHEET_ID + '/values/Sheet1!A:A',
    json: true,
    returnFullResponse: true,
  });
  results.method3 = { type: typeof resp3, keys: Object.keys(resp3 || {}), statusCode: resp3.statusCode, bodyKeys: Object.keys(resp3.body || {}) };
  console.log('Method 3 result: ' + JSON.stringify(results.method3));
} catch(e) {
  results.method3 = { error: e.message };
  console.log('Method 3 error: ' + e.message);
}

// Method 4: Plain httpRequest with public CSV export (no auth needed if sheet is public)
try {
  console.log('Method 4: Public CSV export');
  const csvUrl = 'https://docs.google.com/spreadsheets/d/' + SHEET_ID + '/export?format=csv&gid=0';
  const resp4 = await this.helpers.httpRequest({ method: 'GET', url: csvUrl });
  const lines = (typeof resp4 === 'string' ? resp4 : '').split(String.fromCharCode(10)).filter(l => l.trim());
  results.method4 = { type: typeof resp4, lines: lines.length, first5: lines.slice(0, 5) };
  console.log('Method 4 result: ' + JSON.stringify(results.method4));
} catch(e) {
  results.method4 = { error: e.message };
  console.log('Method 4 error: ' + e.message);
}

return [{ json: results }];
